"""Termination Tribunal

A loop TERMINATES if it is guaranteed to eventually stop running, for whatever inputs it is given. Proving termination, informally, means finding a VARIANT (also called a MEASURE) -- some quantity computed from the loop's variables that (1) is bounded below by some fixed value the loop cannot go past, and (2) strictly decreases by at least a fixed amount every single iteration. If you can name that quantity, the loop must terminate, because a strictly decreasing sequence bounded below cannot decrease forever. This activity puts seven loops on trial: does this loop always terminate, can it loop forever, does it terminate only for some inputs, or -- for exactly one famous case -- is the honest answer that nobody has ever proven it either way? Every explanation names the decreasing-measure argument (or explains exactly why one cannot be found).
"""
import json, sys

# -- Crypto / obfuscation --
_KEY_A = "4560bfb776c32956342db2ee4d2d0b9ff51bc65477614fb83e727ff2721d8d0b"
_KEY_B = "9c0f8ec5788c8e02c77da7345f7887c3c04142b7e5a78b9b8c1077ccc4c51c34"
import base64 as _b64, hashlib as _hl, hmac as _hm, json as _js, zlib as _zl

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000

# Split runtime key. This is obfuscation only; do not treat it as a secret.
def _xor_bytes(a, b):
    return bytes(x ^ y for x, y in zip(a, b))

def _runtime_key():
    return _xor_bytes(bytes.fromhex(_KEY_A), bytes.fromhex(_KEY_B))

def _derive_key(answers):
    return _hl.pbkdf2_hmac("sha256", "|".join(answers).encode(), _SALT, _KDF_ITERS)

def _stream(key, length):
    ks, i = b"", 0
    while len(ks) < length:
        ks += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return ks[:length]

def _decrypt(blob_hex, answers):
    blob    = bytes.fromhex(blob_hex)
    key     = _derive_key(answers)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    return bytes(a ^ b for a, b in zip(ct, _stream(key, len(ct)))).decode()

def _item_key(label):
    return _hm.new(_runtime_key(), label.encode(), _hl.sha256).digest()

def _open_secret(blob_text, label):
    try:
        blob = _b64.b85decode(blob_text.encode())
        key = _item_key(label)
        ct, mac = blob[:-32], blob[-32:]
        if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
            return None
        pt = _xor_bytes(ct, _stream(key, len(ct)))
        data = _js.loads(_zl.decompress(pt).decode())
        return data if isinstance(data, dict) else None
    except Exception:
        return None

